<template>
  <div>
<!--    <SpPlatformTip h5 app alipay />-->
    <el-tabs v-model="activeName" type="card">
      <el-tab-pane
        v-for="(item, index) in tabList"
        :key="index"
        :label="item.name"
        :name="item.activeName"
      >
        <template>
          <el-form ref="form" label-width="130px">
            <el-form-item label="開啟一洽客服">
              <el-switch
                v-model="form.is_open"
                active-value="true"
                inactive-value="false"
                inactive-color="#ccc"
                active-text="開啟"
                inactive-text="關閉"
                active-color="#13ce66"
              />
            </el-form-item>
            <el-form-item label="一洽客服連結地址">
              <el-input v-model="form.echat_url" style="width: 300px" placeholder="請輸入內容" />
            </el-form-item>

            <div class="section-footer with-border content-center">
              <el-button type="primary" @click="onSubmit"> 一洽客服儲存 </el-button>
            </div>
          </el-form>
        </template>
      </el-tab-pane>
    </el-tabs>
  </div>
</template>

<script>
import { getECahtSetting, saveEChatSetting } from '../../../../api/im'

export default {
  data() {
    return {
      loading: false,
      form: {
        is_open: '',
        echat_url: ''
      },
      activeName: 'first',
      tabList: [{ name: '客服配置', activeName: 'first' }]
    }
  },
  mounted() {
    this.getInfo()
  },
  methods: {
    getInfo() {
      getECahtSetting().then((response) => {
        this.form = response.data.data
      })
    },
    onSubmit() {
      saveEChatSetting(this.form)
        .then((response) => {
          this.$message({ message: '儲存成功', type: 'success' })
          this.getInfo()
        })
        .catch()
    }
  }
}
</script>
<style lang="scss" scoped></style>
